            background-color: #4CAF50;
            color: white;
            display: flex;
            justify-content: center;
            align-items: center;
            position: absolute;
            cursor: pointer;
        }
        .edge {
            position: absolute;
            height: 2px;
            background-color: #333;
            transform-origin: 0 0;
        }
        .visited {
